head.script:
//==================================================================================================================
// id       : fs_102_01_16p 
// 이름     : 거래명세서번호 조회
// 경로     : 물류/정산/매입승인/철송비용 매입 승인/
// 작 성 자 : 조성빈
// 작 업 일 : 2026-02-26
// 사용계정 : 내부
// 비고     :  ***
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = async function() {

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        ica_pchsIntendDtSt.setValue($c.data.getParameter("pchsIntendDtSt"));  // 매입예정일자시작
		ica_pchsIntendDtEnd.setValue($c.data.getParameter("pchsIntendDtEnd"));  // 매입예정일자종료		
		scwin.f_RetrieveCertiNumberList();

		ica_pchsIntendDtSt.focus();

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 거래명세서번호 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCertiNumberList = async function () {
    // 검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([ica_pchsIntendDtSt, ica_pchsIntendDtEnd])) {
        return;
    }

    if (!await $c.gus.cfIsAfterDate(ica_pchsIntendDtSt.getValue(), ica_pchsIntendDtEnd.getValue())) {
        await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_pchsIntendDtSt.focus();
        return;
    }

    ds_searchCertiNumberList.set("pchsDeptCd", $c.data.getParameter("pchsDeptCd")); // 매입점소
    ds_searchCertiNumberList.set("pchsClntNo", $c.data.getParameter("pchsClntNo"));  // 매입거래처
    ds_searchCertiNumberList.set("selpchItemCd", $c.data.getParameter("selpchItemCd"));  // 매출입항목코드
    ds_searchCertiNumberList.set("pchsGoodsPatternCd", $c.data.getParameter("pchsGoodsPatternCd"));  // 매입품목유형코드				

    $c.sbm.execute(sbm_searchCertiNumberList)
};	

//-------------------------------------------------------------------------
// 닫기
//-------------------------------------------------------------------------
scwin.f_WinClose = function () {
    $c.win.closePopup();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_RetrieveCertiNumberList();
};

scwin.btn_close_onclick = function (e) {
    scwin.f_WinClose();
};

scwin.sbm_searchCertiNumberList_submitdone = async function (e) {
    // 총 조회건수 표시
    var rowCnt = ds_certiNumberList.getRowCount();
    txt_totalRows.setValue(rowCnt);
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } 
};

scwin.gr_certiNumberList_oncelldblclick = function (row, columnIndex, columnId) {
    // 객체를 생성하고, 그 안의 변수에 값을 설정해 리턴
    var objReturn = new Object();
    objReturn.certiNo = ds_certiNumberList.getCellData(row, 'certiNo');  // 거래명세서번호
    objReturn.rmk = ds_certiNumberList.getCellData(row, 'rmk');  // 비고

    $c.win.closePopup(objReturn);
};
